import React, { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

function DaysReport() {
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");

  const [allRequests, setAllRequests] =
    useState([]);

  const [filteredData, setFilteredData] =
    useState([]);

  const fetchCompletedRequests =
    async () => {
      try {
        const res = await axios.get(
          Api.get_All_Emg_Req
        );

        const data =
          res.data?.data ||
          res.data?.requests ||
          res.data ||
          [];

        const completedOnly =
          data.filter(
            (req) =>
              req.status === "Completed"
          );

        setAllRequests(completedOnly);
      } catch (err) {
        console.log(err);
      }
    };

  useEffect(() => {
    fetchCompletedRequests();
  }, []);

  const handleSearch = () => {
    if (!fromDate || !toDate) {
      return alert(
        "Select From and To Date"
      );
    }

    const filtered =
      allRequests.filter((req) => {
        const completedDate =
          new Date(req.completedAt);

        return (
          completedDate >=
            new Date(fromDate) &&
          completedDate <=
            new Date(
              `${toDate}T23:59:59`
            )
        );
      });

    setFilteredData(filtered);
  };

  return (
    <div className="min-h-screen bg-green-50 p-8">
      <div className="max-w-7xl mx-auto">

        <div className="bg-white rounded-2xl shadow-lg p-6 mb-8">
          <h1 className="text-4xl font-bold text-green-900 mb-6">
            Days Report
          </h1>

          <div className="grid md:grid-cols-3 gap-4">

            <div>
              <label className="font-semibold block mb-2">
                From Date
              </label>

              <input
                type="date"
                value={fromDate}
                onChange={(e) =>
                  setFromDate(
                    e.target.value
                  )
                }
                className="w-full border rounded-lg p-3"
              />
            </div>

            <div>
              <label className="font-semibold block mb-2">
                To Date
              </label>

              <input
                type="date"
                value={toDate}
                onChange={(e) =>
                  setToDate(
                    e.target.value
                  )
                }
                className="w-full border rounded-lg p-3"
              />
            </div>

            <div className="flex items-end">
              <button
                onClick={handleSearch}
                className="w-full bg-green-800 text-white py-3 rounded-lg hover:bg-green-900"
              >
                Generate Report
              </button>
            </div>

          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-lg p-6">

          <div className="flex justify-between mb-6">

            <h2 className="text-2xl font-bold text-green-900">
              Completed Records
            </h2>

            <span className="bg-green-100 text-green-800 px-4 py-2 rounded-full">
              Total: {filteredData.length}
            </span>

          </div>

          {filteredData.length === 0 ? (
            <div className="text-center py-10 text-gray-500">
              No records found
            </div>
          ) : (
            <div className="overflow-x-auto">

              <table className="w-full border">

                <thead>
                  <tr className="bg-green-900 text-white">

                    <th className="p-3">
                      Location
                    </th>

                    <th className="p-3">
                      Priority
                    </th>

                    <th className="p-3">
                      Created
                    </th>

                    <th className="p-3">
                      Scheduled
                    </th>

 <th className="p-3">
                      Arrived
                    </th>

                    <th className="p-3">
                      Completed
                    </th>

                  </tr>
                </thead>

                <tbody>

                  {filteredData.map(
                    (req) => (
                      <tr
                        key={req._id}
                        className="border-b hover:bg-green-50"
                      >
                        <td className="p-3">
                          {
                            req.location
                              ?.locationName
                          }
                        </td>

                        <td className="p-3">
                          {req.priority}
                        </td>

                        <td className="p-3">
                          {new Date(
                            req.createdAt
                          ).toLocaleString(
                            "en-IN"
                          )}
                        </td>

                        <td className="p-3">
                          {req.scheduledDate
                            ? `${req.scheduledDate} | ${req.scheduledTime}`
                            : "-"}
                        </td>

           <td className="p-3">
                          {req.arrivedAt
                            ? `${req.arrivedAt} | ${req.scheduledTime}`
                            : "-"}
                        </td>
                        <td className="p-3 text-green-700 font-semibold">
                          {new Date(
                            req.completedAt
                          ).toLocaleString(
                            "en-IN"
                          )}
                        </td>
                      </tr>
                    )
                  )}

                </tbody>

              </table>

            </div>
          )}

        </div>
      </div>
    </div>
  );
}

export default DaysReport;
